create table dirkspzm32.s_sas_sap_send_bew (
    send_id            number(*, 0) not null enable,
    ts                 date not null enable,
    sap_fb             varchar2(30 char) not null enable,
    slb_buchnr         number(*, 5),
    slb_mat_nr         varchar2(6 char),
    slb_charge         varchar2(8 char),
    slb_menge          number(*, 3),
    slb_von_lgr_ort    varchar2(4 char),
    slb_nach_lgr_ort   varchar2(4 char),
    slb_first_scan     date,
    slb_last_scan      date,
    slb_meins          varchar2(3 char),
    status             varchar2(10 char),
    slb_fb_ret_code    number(*, 5),
    slb_fb_ret_message varchar2(50 char),
    slb_cycle          varchar2(2 char),
    slb_exp_status     number(4, 0),
    slb_auftrnr        varchar2(20 char)
);


